class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with checkers pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('white', (row, col))
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('black', (row, col))

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece) if piece else '  ' for piece in row]))

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if piece:
            piece.position = to_pos
            self.board[from_pos[0]][from_pos[1]] = None
            self.board[to_pos[0]][to_pos[1]] = piece

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.king = False

    def __str__(self):
        if self.color == 'white':
            return 'W' if not self.king else 'WK'
        else:
            return 'B' if not self.king else 'BK'

if __name__ == "__main__":
