from models.board import Board

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'white'

    def start(self):
        while True:
            print(f"Current player: {self.current_player}")
            self.board.print_board()
            move = input("Enter your move (from-to): ").split('-')
            from_pos = tuple(int(pos.strip()) for pos in move[0].split(','))
            to_pos = tuple(int(pos.strip()) for pos in move[1].split(','))
            if self.is_valid_move(from_pos, to_pos):
                self.board.move_piece(from_pos, to_pos)
                self.switch_player()
            else:
                print("Invalid move. Please try again.")

    def is_valid_move(self, from_pos, to_pos):
        piece = self.board.get_piece(from_pos)
        return piece and piece.color == self.current_player and self.board.get_piece(to_pos) is None

    def switch_player(self):
        self.current_player = 'black' if self.current_player == 'white' else 'white'

if __name__ == "__main__":
    game = Game()
    game.start()
